"use strict";(()=>{chrome.commands.onCommand.addListener(async i=>{if(i==="fill-form"){let[e]=await chrome.tabs.query({active:!0,currentWindow:!0});if(!e?.id)return;chrome.tabs.sendMessage(e.id,{type:"FILL_WITH_SHORTCUT"})}});chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"quickfill-fill",title:"QuickFill \u2014 Fill this form",contexts:["page","editable"]})});chrome.contextMenus.onClicked.addListener(async(i,e)=>{i.menuItemId==="quickfill-fill"&&e?.id&&chrome.tabs.sendMessage(e.id,{type:"FILL_WITH_SHORTCUT"})});chrome.runtime.onMessage.addListener((i,e,s)=>(i.type==="OPEN_OPTIONS"&&(chrome.runtime.openOptionsPage(),s({ok:!0})),!1));})();
